-- {"operators": "INNER_JOIN,AGGREGATE,ORDER,WINDOW,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
WITH o_totals AS (SELECT OL_W_ID, OL_O_ID, OL_D_ID, SUM(OL_AMOUNT) AS order_amt FROM dl.ORDER_LINE GROUP BY OL_W_ID, OL_O_ID, OL_D_ID) SELECT c.C_W_ID, c.C_ID, c.C_LAST, SUM(ot.order_amt) AS spent, RANK() OVER (PARTITION BY c.C_W_ID ORDER BY SUM(ot.order_amt) DESC) AS spend_rank FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN o_totals ot ON o.O_W_ID = ot.OL_W_ID AND o.O_D_ID = ot.OL_D_ID AND o.O_ID = ot.OL_O_ID GROUP BY c.C_W_ID, c.C_ID, c.C_LAST;
